function addBug(d,notify=false){
  const id=seq++;
  const bug={id,title:d.title,severity:d.sev,category:d.cat,desc:d.desc,steps:d.steps||'',reporter:d.reporter,email:d.email,status:d.status||'Open',os:d.os||'',browser:d.browser||'',ver:d.ver||'—',env:d.env||'',assigned:d.assigned||'Unassigned',date:new Date(Date.now()-Math.random()*28*864e5).toISOString(),priority:{Critical:4,High:3,Medium:2,Low:1}[d.sev]||1,notes:d.notes||''};
  bugs[id]=bug;audit[id]=new AuditStack();
  audit[id].push({action:`Filed by ${bug.reporter}`,status:'Open'});
  if(bug.status==='In Progress')audit[id].push({action:'Assigned — moved to In Progress',status:'In Progress'});
  if(bug.status==='Resolved'){audit[id].push({action:'Moved to In Progress',status:'In Progress'});audit[id].push({action:'Marked Resolved',status:'Resolved'});}
  if(bug.status==='Closed'){audit[id].push({action:'Moved to In Progress',status:'In Progress'});audit[id].push({action:'Marked Resolved',status:'Resolved'});audit[id].push({action:'Filed as Closed',status:'Closed'});}
  heap.rebuild(Object.values(bugs).filter(b=>b.status==='Open'||b.status==='In Progress'));
  bug.title.split(/\s+/).forEach(w=>trie.insert(w,id));
  if(notify){nq.push({title:`New Filing: BUG-${pad(id)}`,msg:`"${bug.title.slice(0,45)}"`,ico:'📝'});if(bug.severity==='Critical')nq.push({title:'⚠ CRITICAL DEFECT FILED',msg:bug.title.slice(0,50),ico:'🚨'});}
  return id;
}
seeds.forEach(s=>addBug(s));

/* ═══ AUTH & SESSION ═══ */
function checkAuth(requiredRole) {
  const session = localStorage.getItem('bugTrackerSession');
  if (!session) {
    window.location.href = 'index.html';
    return;
  }
  
  try {
    const data = JSON.parse(session);
    loggedUser = data.loggedUser;
    selectedRole = data.role;
    window.currentRole = data.role;
    
    // Check role permission
    if (requiredRole && requiredRole !== selectedRole) {
      toast('Access denied - wrong role', 'e');
      setTimeout(() => {
        // Redirect to their correct home page
        if (selectedRole === 'developer') window.location.href = 'developer-home.html';
        else if (selectedRole === 'tester') window.location.href = 'tester-home.html';
        else window.location.href = 'user-home.html';
      }, 1000);
      return;
    }
  } catch(e) {
    window.location.href = 'index.html';
  }
}

