/* ═══ NOTIF ═══ */
nq.on(()=>{
  const u=nq.unread();
  const bc=document.getElementById('bellCount');
  if(bc){bc.textContent=u;bc.style.display=u>0?'inline':'none';}
  renderNP();
});
function renderNP(){
  const el=document.getElementById('npList');if(!el)return;
  const all=nq.all();
  if(!all.length){el.innerHTML='<div class="np-empty">No dispatches on record.</div>';return;}
  el.innerHTML=all.slice(0,12).map(n=>`<div class="np-item ${n.read?'':'unread'}"><div class="np-ico">${n.ico||'🔔'}</div><div class="np-body"><div class="np-title2">${n.title}</div><div class="np-msg">${n.msg||''}</div><div class="np-time">${ago(n.ts)}</div></div></div>`).join('');
}
function toggleBell(){const p=document.getElementById('notifPanel');p.classList.toggle('open');if(p.classList.contains('open'))nq.markRead();}
function clearNotifs(){nq.clear();}
document.addEventListener('click',e=>{const p=document.getElementById('notifPanel');const b=document.querySelector('.bell-wrap');if(b&&!b.contains(e.target))p?.classList.remove('open');});

/* ═══ ACCOUNT STORE ═══ */
// Stores registered accounts as: { username, email, password, role, firstName, lastName }
let accounts = [];

// Load accounts from localStorage on page load
function loadAccounts() {
  const stored = localStorage.getItem('bugTrackerAccounts');
  if (stored) {
    try {
      accounts = JSON.parse(stored);
    } catch (e) {
      accounts = [];
    }
  }
}

// Save accounts to localStorage
function saveAccounts() {
  localStorage.setItem('bugTrackerAccounts', JSON.stringify(accounts));
}

// Load accounts when script loads
loadAccounts();

