/* ═══ PASSWORD STRENGTH ═══ */
document.addEventListener('DOMContentLoaded', ()=>{
  const pwdInput = document.getElementById('r-pwd');
  if (pwdInput) {
    pwdInput.addEventListener('input', ()=>{
      const val = pwdInput.value;
      const bar  = document.getElementById('pwdFill');
      const lbl  = document.getElementById('pwdLabel');
      const wrap = document.getElementById('pwdStrength');
      if (!val) { wrap.style.display='none'; return; }
      wrap.style.display='flex';
      let score = 0;
      if (val.length >= 6)  score++;
      if (val.length >= 10) score++;
      if (/[A-Z]/.test(val)) score++;
      if (/[0-9]/.test(val)) score++;
      if (/[^A-Za-z0-9]/.test(val)) score++;
      const levels = [
        { w:'20%',  col:'var(--rust)',   t:'Weak'   },
        { w:'40%',  col:'var(--sienna)', t:'Fair'   },
        { w:'60%',  col:'#A0832A',       t:'Good'   },
        { w:'80%',  col:'var(--olive)',  t:'Strong' },
        { w:'100%', col:'#3a7d44',       t:'Excellent'},
      ];
      const lvl = levels[Math.min(score, levels.length) - 1] || levels[0];
      bar.style.width      = lvl.w;
      bar.style.background = lvl.col;
      lbl.style.color      = lvl.col;
      lbl.textContent      = lvl.t;
    });
  }
});

/* ═══ PASSWORD VISIBILITY TOGGLE ═══ */
function togglePwd(inputId, eyeId) {
  const inp = document.getElementById(inputId);
  const eye = document.getElementById(eyeId);
  if (!inp) return;
  const isHidden = inp.type === 'password';
  inp.type   = isHidden ? 'text' : 'password';
  eye.textContent = isHidden ? '🙈' : '👁';
}

/* ═══ REGISTER ═══ */
function doRegister() {
  const fname = document.getElementById('r-fname').value.trim();
  const lname = document.getElementById('r-lname').value.trim();
  const email = document.getElementById('r-email').value.trim();
  const uname = document.getElementById('r-uname').value.trim();
  const role  = document.getElementById('r-role').value;
  const pwd   = document.getElementById('r-pwd').value;
  const pwd2  = document.getElementById('r-pwd2').value;
  const terms = document.getElementById('r-terms').checked;

  // Validation
  if (!fname || !lname)        { toast('Please enter your full name','e'); return; }
  if (!email || !email.includes('@')) { toast('Please enter a valid email address','e'); return; }
  if (!uname || uname.length < 3)    { toast('Username must be at least 3 characters','e'); return; }
  if (!/^[a-zA-Z0-9.]+$/.test(uname)){ toast('Username: letters, numbers and dots only','e'); return; }
  if (!role)                         { toast('Please select a role','e'); return; }
  if (!pwd || pwd.length < 6)        { toast('Password must be at least 6 characters','e'); return; }
  if (pwd !== pwd2)                  { toast('Passwords do not match','e'); return; }
  if (!terms)                        { toast('Please accept the Terms of Registry','e'); return; }

  // Duplicate check
  if (accounts.find(a => a.username === uname)) { toast('Username already taken — choose another','e'); return; }
  if (accounts.find(a => a.email === email))     { toast('Email already registered — sign in instead','e'); return; }

  // Save account
  accounts.push({ username: uname, email, password: pwd, role, firstName: fname, lastName: lname });
  saveAccounts();

  toast(`Account created! Welcome ${fname}.`,'s');

  // Automatically log in the user and redirect to home page
  setTimeout(() => {
    // Set logged user name
    loggedUser = `${fname} ${lname}`;
    selectedRole = role;
    
    // Update sidebar with user info
    document.getElementById('sb-uname').textContent = loggedUser;
    document.getElementById('sb-av').textContent = loggedUser.split(' ').map(w=>w[0]).join('').toUpperCase().slice(0,2);
    
    // Show role badge in sidebar
    const roleLabel = {developer:'Developer',tester:'Tester',user:'User'}[role];
    const roleColor = {developer:'var(--sienna)',tester:'var(--olive)',user:'var(--slate)'}[role];
    document.getElementById('sb-user-role-el').textContent = roleLabel;
    document.getElementById('sb-user-role-el').style.color = roleColor;
    
    // Update topbar
    document.getElementById('topbarTitle').textContent = `Bug Tracker — ${roleLabel} Portal`;
    
    // Hide register page, show app
    document.getElementById('page-register').classList.remove('active');
    const app = document.getElementById('page-app');
    app.classList.add('active','page-app');
    
    // Apply role-based sidebar restrictions
    applyRoleUI(role);
    buildAllInners();
    
    // Route to home page
    showInner('home');
    
    // Send welcome notification
    nq.push({title:`Welcome, ${roleLabel}`,msg:`Account created for ${loggedUser}`,ico:'👋'});
    toast(`Welcome ${fname} — ${roleLabel} access granted`,'s');
  }, 800);
}

/* ═══ ROLE SELECTION ═══ */
let selectedRole = null;
function selectRole(role) {
  selectedRole = role;
  ['developer','tester','user'].forEach(r => {
    const card = document.getElementById('rc-'+r);
    const chk  = document.getElementById('chk-'+r);
    if (r === role) {
      card.style.borderColor = 'var(--gold)';
      card.style.background  = 'rgba(200,149,42,.15)';
      chk.textContent = '✓';
      chk.style.background     = 'var(--gold)';
      chk.style.borderColor    = 'var(--gold)';
      chk.style.color          = 'var(--ink2)';
    } else {
      card.style.borderColor = 'rgba(200,149,42,.25)';
      card.style.background  = 'rgba(255,255,255,.05)';
      chk.textContent = '';
      chk.style.background  = 'transparent';
      chk.style.borderColor = 'rgba(200,149,42,.4)';
    }
  });
  document.getElementById('role-required').style.display = 'none';
}

/* ═══ LOGIN ═══ */
function doLogin(){
  const u = document.getElementById('l-user').value.trim();
  const p = document.getElementById('l-pass').value.trim();
  if (!u || !p) { toast('Please enter credentials','e'); return; }
  if (!selectedRole) {
    document.getElementById('role-required').style.display = 'block';
    toast('Please select a role first','e'); return;
  }
  
  loggedUser = u.split('@')[0].split('.').map(w=>w.charAt(0).toUpperCase()+w.slice(1)).join(' ');
  
  // Save session
  localStorage.setItem('bugTrackerSession', JSON.stringify({
    loggedUser,
    role: selectedRole,
    loginTime: Date.now()
  }));
  
  toast(`Welcome ${loggedUser}`, 's');
  
  // Redirect to role-specific home page
  setTimeout(() => {
    if (selectedRole === 'developer') {
      window.location.href = 'developer-home.html';
    } else if (selectedRole === 'tester') {
      window.location.href = 'tester-home.html';
    } else {
      window.location.href = 'user-home.html';
    }
  }, 500);
}
function doLogout(){
  localStorage.removeItem('bugTrackerSession');
  toast('Signed out successfully','s');
  setTimeout(() => window.location.href = 'index.html', 500);
}

/* ═══ ROLE-BASED UI ═══ */
function applyRoleUI(role) {
  // Developer: full sidebar visible
  // Tester: hide no pages, but restrict actions
  // User: hide dashboard, about, contact from sidebar
  const hideForUser   = ['sl-dashboard','sl-about','sl-contact'];
  const hideForTester = [];
  if (role === 'user') {
    hideForUser.forEach(id => { const el=document.getElementById(id); if(el) el.style.display='none'; });
  }
  // Store role globally for access checks
  window.currentRole = role;
}

function canDoDevAction() {
  if (window.currentRole !== 'developer') {
    toast('This action requires Developer access','e'); return false;
  }
  return true;
}

/* ═══ PAGE ROUTING ═══ */
const titles={home:'The Registry — Home',dashboard:'The Registry — Dashboard',bugs:'Bug Tracker — Full Ledger',report:'File a New Bug Report',about:'About the Bureau',contact:'Correspondence'};
function showInner(pg){
  document.querySelectorAll('.inner').forEach(e=>e.style.display='none');
  document.querySelectorAll('.sb-link').forEach(l=>l.classList.remove('active'));
  document.getElementById('inner-'+pg).style.display='flex';
  document.getElementById('inner-'+pg).style.flexDirection='column';
  const sl=document.getElementById('sl-'+pg);if(sl)sl.classList.add('active');
  document.getElementById('topbarTitle').textContent=titles[pg]||'BugTracker';
  if(pg==='dashboard')refreshDash();
  if(pg==='bugs')renderBugsPage();
  if(pg==='home')buildHome();
  window.scrollTo(0,0);
}

/* ═══ HELPERS ═══ */
function pad(id){return String(id).padStart(4,'0');}
function ago(d){const s=Math.floor((Date.now()-new Date(d))/1000);if(s<60)return'just now';if(s<3600)return`${Math.floor(s/60)}m ago`;if(s<86400)return`${Math.floor(s/3600)}h ago`;return`${Math.floor(s/86400)}d ago`;}
function fmtDate(d){return new Date(d).toLocaleDateString('en-IN',{day:'numeric',month:'short',year:'numeric'});}
function avCol(n){const cs=['#3D2B1F','#6B3A22','#5C6B2E','#4A3020','#8B4513','#2C4A3A'];let h=0;for(const c of n)h+=c.charCodeAt(0);return cs[h%cs.length];}
function ini(n){return n.split(' ').map(w=>w[0]).join('').toUpperCase().slice(0,2);}
function sevBadge(s){const m={Critical:'b-critical',High:'b-high',Medium:'b-medium',Low:'b-low'};return`<span class="badge ${m[s]||'b-low'}">${s}</span>`;}
function stBadge(s){const m={'Open':'b-open','In Progress':'b-inprog','Resolved':'b-resolved','Closed':'b-closed'};return`<span class="badge ${m[s]||'b-open'}">${s}</span>`;}
function sevDot(s){const m={Critical:'sd-c',High:'sd-h',Medium:'sd-m',Low:'sd-l'};return`<span class="sev-dot ${m[s]||'sd-l'}"></span>`;}
function countUp(id,t){const el=document.getElementById(id);if(!el)return;let n=0;const s=Math.max(1,Math.ceil(t/20));const it=setInterval(()=>{n=Math.min(n+s,t);el.textContent=n;if(n>=t)clearInterval(it);},50);}

function toast(msg,type='i'){
  const ic={s:'✓',e:'✕',i:'◆',w:'⚠'};
  const d=document.createElement('div');
  d.className=`toast t-${type}`;
  d.innerHTML=`<span class="t-ico">${ic[type]||'◆'}</span><span class="t-msg">${msg}</span>`;
  document.getElementById('toastWrap').appendChild(d);
  setTimeout(()=>d.remove(),4200);
}

