function refreshDash(){
  const all=Object.values(bugs);
  countUp('ds-total',all.length);
  countUp('ds-open',all.filter(b=>b.status==='Open').length);
  countUp('ds-ip',all.filter(b=>b.status==='In Progress').length);
  countUp('ds-res',all.filter(b=>b.status==='Resolved'||b.status==='Closed').length);
  // PQ
  const top=heap.peek(6),pqEl=document.getElementById('ds-pq');
  if(!pqEl)return;
  pqEl.innerHTML=top.length?`<table><thead><tr><th>#</th><th>Title</th><th>Severity</th><th>Status</th></tr></thead><tbody>`+
    top.map((b,i)=>`<tr class="clickable" onclick="openBugModal(${b.id})"><td class="mono" style="color:var(--ink3);font-size:11px;">${i+1}</td><td style="font-weight:600;font-size:13px;max-width:220px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${b.title}</td><td>${sevBadge(b.severity)}</td><td>${stBadge(b.status)}</td></tr>`).join('')+'</tbody></table>'
    :'<div class="empty-state"><div class="empty-ico">✅</div><div class="empty-txt">No active filings</div></div>';
  // Recent
  const rb=Object.values(bugs).sort((a,b)=>new Date(b.date)-new Date(a.date)).slice(0,6);
  const re=document.getElementById('ds-recent');
  if(re)re.innerHTML=rb.map(b=>`<tr class="clickable" onclick="openBugModal(${b.id})"><td class="mono" style="font-size:11px;color:var(--sienna);">BUG-${pad(b.id)}</td><td style="font-size:13px;max-width:180px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;font-weight:500;">${b.title}</td><td>${sevBadge(b.severity)}</td><td>${stBadge(b.status)}</td></tr>`).join('');
  // Sev chart
  const c={Critical:0,High:0,Medium:0,Low:0};all.forEach(b=>c[b.severity]++);const tot=all.length||1;
  const se=document.getElementById('ds-sev');
  if(se)se.innerHTML=[{l:'Critical',c:c.Critical,col:'var(--rust)'},{l:'High',c:c.High,col:'var(--sienna)'},{l:'Medium',c:c.Medium,col:'#A0832A'},{l:'Low',c:c.Low,col:'var(--olive)'}].map(r=>`<div style="margin-bottom:15px;"><div style="display:flex;justify-content:space-between;font-size:12px;margin-bottom:5px;"><span style="font-family:'Courier Prime',monospace;font-weight:700;color:${r.col};text-transform:uppercase;letter-spacing:.5px;">${r.l}</span><span style="color:var(--ink3);font-family:'Courier Prime',monospace;">${r.c}</span></div><div class="prog-track"><div class="prog-fill" style="width:${Math.round(r.c/tot*100)}%;background:${r.col};"></div></div></div>`).join('');
  // Activity
  const ae=document.getElementById('ds-activity');
  if(ae){const items=[];Object.values(bugs).sort((a,b)=>new Date(b.date)-new Date(a.date)).slice(0,8).forEach(b=>{const a=audit[b.id];if(a){const l=a.list()[0];if(l)items.push({...l,bug:b});}});ae.innerHTML=items.slice(0,6).map(it=>`<div style="display:flex;gap:10px;align-items:flex-start;padding:10px;background:var(--parch);border:1px solid var(--parch3);border-radius:var(--r);"><div class="avatar" style="background:${avCol(it.bug.reporter)}">${ini(it.bug.reporter)}</div><div><div style="font-size:12px;font-weight:600;color:var(--ink2);font-family:'Lora',serif;">${it.action}</div><div style="font-size:11px;color:var(--ink3);margin-top:2px;font-family:'Courier Prime',monospace;">BUG-${pad(it.bug.id)} · ${ago(it.ts)}</div></div></div>`).join('');}
}

