function rStep2(){const t=document.getElementById('r-title')?.value.trim(),s=document.getElementById('r-sev')?.value,d=document.getElementById('r-desc')?.value.trim(),n=document.getElementById('r-name')?.value.trim(),e=document.getElementById('r-email')?.value.trim();if(!t){toast('Please enter a defect title','e');return;}if(!s){toast('Please select severity','e');return;}if(!d){toast('Please describe the defect','e');return;}if(!n){toast('Please enter your name','e');return;}if(!e||!e.includes('@')){toast('Please enter a valid email','e');return;}rData={title:t,sev:s,cat:document.getElementById('r-cat')?.value,desc:d,steps:document.getElementById('r-steps')?.value.trim(),reporter:n,email:e};document.getElementById('rs1').style.display='none';document.getElementById('rs2').style.display='block';setStepper(2);}
function rStep1(){document.getElementById('rs2').style.display='none';document.getElementById('rs1').style.display='block';setStepper(1);}
function rStep3(){rData.os=document.getElementById('r-os')?.value;rData.browser=document.getElementById('r-browser')?.value;rData.ver=document.getElementById('r-ver')?.value||'—';rData.env=document.getElementById('r-env')?.value;rData.notes=document.getElementById('r-notes')?.value.trim();document.getElementById('rs2').style.display='none';document.getElementById('rs3').style.display='block';setStepper(3);document.getElementById('rs3card').innerHTML=`<div class="card-hd"><div class="card-title">◆ Review Your Filing</div></div><div class="card-body"><div class="grid-2" style="margin-bottom:16px;"><div><div class="form-label">Title</div><div style="font-size:14px;font-weight:600;font-family:'Lora',serif;">${rData.title}</div></div><div><div class="form-label">Severity</div>${sevBadge(rData.sev)}</div></div><div class="rule" style="margin:12px 0;"></div><div style="margin-bottom:14px;"><div class="form-label">Description</div><p style="font-size:14px;color:var(--ink3);line-height:1.6;font-style:italic;">${rData.desc}</p></div>${rData.steps?`<div style="margin-bottom:14px;"><div class="form-label">Steps</div><pre style="font-size:12px;font-family:'Courier Prime',monospace;color:var(--ink3);white-space:pre-wrap;background:var(--parch);padding:10px;border:1px solid var(--parch3);border-radius:var(--r);">${rData.steps}</pre></div>`:''}<div class="rule" style="margin:12px 0;"></div><div class="grid-2"><div><div class="form-label">Reporter</div><div style="font-size:13px;">${rData.reporter}</div></div><div><div class="form-label">Email</div><div style="font-size:13px;color:var(--ink3);font-style:italic;">${rData.email}</div></div><div><div class="form-label">OS</div><div style="font-size:13px;color:var(--ink3);">${rData.os}</div></div><div><div class="form-label">Browser</div><div style="font-size:13px;color:var(--ink3);">${rData.browser}</div></div></div></div>`;}
function rStep2back(){document.getElementById('rs3').style.display='none';document.getElementById('rs2').style.display='block';setStepper(2);}
function setStepper(n){[1,2,3].forEach(i=>{const s=document.getElementById('si-'+i);if(s)s.className='step-item'+(i<n?' s-done':i===n?' s-active':'');});}
function submitReport(){
  const id=addBug({...rData,status:'Open',assigned:'Unassigned'},true);
  toast(`Filing registered — BUG-${pad(id)}`,'s');
  ['r-title','r-desc','r-steps','r-name','r-email','r-ver','r-notes'].forEach(x=>{const e=document.getElementById(x);if(e)e.value='';});
  const sv=document.getElementById('r-sev');if(sv)sv.value='';
  document.getElementById('rs3').style.display='none';
  document.getElementById('rs1').style.display='block';
  setStepper(1);
  
  // Redirect based on role
  const session = localStorage.getItem('bugTrackerSession');
  if (session) {
    const data = JSON.parse(session);
    setTimeout(()=>{
      if (data.role === 'developer') {
        window.location.href='developer-bugs.html';
      } else if (data.role === 'tester') {
        window.location.href='tester-home.html';
      } else {
        window.location.href='user-home.html';
      }
    }, 600);
  }
}

