function submitContact(){
  const fn=document.getElementById('c-fn')?.value.trim(),ln=document.getElementById('c-ln')?.value.trim(),em=document.getElementById('c-em')?.value.trim(),msg=document.getElementById('c-msg')?.value.trim();
  if(!fn||!ln){toast('Please enter your name','e');return;}
  if(!em||!em.includes('@')){toast('Please enter a valid email','e');return;}
  if(!msg){toast('Please enter a message','e');return;}
  nq.push({title:'Dispatch Received',msg:`Thank you ${fn}. We'll reply to ${em} within 24 hours.`,ico:'📬'});
  toast(`Dispatch sent. We'll reply to ${em} within 24 hours.`,'s');
  ['c-fn','c-ln','c-em','c-msg'].forEach(id=>{const e=document.getElementById(id);if(e)e.value='';});
}

/* ─── LOGIN STATS ─── */
function setLoginStats(){
  const all=Object.values(bugs);
  let n=0;const ti=setInterval(()=>{n=Math.min(n+1,all.length);const e=document.getElementById('ls-total');if(e)e.textContent=n;if(n>=all.length)clearInterval(ti);},60);
  let r=0;const ri=setInterval(()=>{r=Math.min(r+1,all.filter(b=>b.status==='Resolved'||b.status==='Closed').length);const e=document.getElementById('ls-resolved');if(e)e.textContent=r;if(r>=all.filter(b=>b.status==='Resolved'||b.status==='Closed').length)clearInterval(ri);},80);
}

/* ─── MODAL CLOSE ON BG ─── */
document.getElementById('bugModal').addEventListener('click',e=>{if(e.target===document.getElementById('bugModal'))closeModal();});

/* ─── ENTER KEY LOGIN ─── */
document.addEventListener('keydown',e=>{if(e.key==='Enter'&&document.getElementById('page-login').classList.contains('active'))doLogin();});

/* ─── INIT ─── */
setLoginStats();

/* ─── AUTO-LOGIN FROM ACCOUNT CREATION ─── */
// When redirected from account.html, automatically log in the user
document.addEventListener('DOMContentLoaded', ()=>{
  const raw = localStorage.getItem('bugTrackerAutoLogin');
  if (!raw) return;
  
  try {
    const data = JSON.parse(raw);
    // Clear the token immediately so it only works once
    localStorage.removeItem('bugTrackerAutoLogin');
    
    // Save session
    localStorage.setItem('bugTrackerSession', JSON.stringify({
      loggedUser: `${data.firstName} ${data.lastName}`,
      role: data.role,
      loginTime: Date.now()
    }));
    
    toast(`Welcome ${data.firstName}!`, 's');
    
    // Redirect to role-specific home page
    setTimeout(() => {
      if (data.role === 'developer') {
        window.location.href = 'developer-home.html';
      } else if (data.role === 'tester') {
        window.location.href = 'tester-home.html';
      } else {
        window.location.href = 'user-home.html';
      }
    }, 800);
  } catch(e) { 
    // If there's an error, just clear the token and continue normally
    localStorage.removeItem('bugTrackerAutoLogin');
  }
});